import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>User Input: " + encodeHtml(userInput) + "</h1>"); // Encode user input before outputting
        out.println("</body>");
        out.println("</html>");
    }

    private String encodeHtml(String input) {
        if (input == null) {
            return "";
        }
        // Replace special HTML characters with their corresponding HTML entities
        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
